SET NAMES utf8mb4;

CREATE TABLE `material_cutting_logs`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `item` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL,
  `log_date` date NULL DEFAULT NULL,
  `log_time` time NULL DEFAULT NULL,
  `hd_no` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL,
  `operator_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL,
  `material_cd` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL,
  `manufacture_no` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '製造番号（材料コードより自動算出）',
  `management_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL,
  `raw_line` text CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL,
  `source_file` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `id`(`id` ASC) USING BTREE,
  INDEX `idx_mcl_log_date`(`log_date` ASC) USING BTREE,
  INDEX `idx_mcl_hd_no`(`hd_no` ASC) USING BTREE,
  INDEX `idx_mcl_material_cd`(`material_cd` ASC) USING BTREE,
  INDEX `idx_mcl_management_code`(`management_code` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2184 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_bin ROW_FORMAT = Dynamic;
